#[async_trait]
impl<R: ImpersonationSessionProjectionRepository> ImpersonationSessionEventHandler for ImpersonationSessionProjector<R> {

    async fn on_created(&self, event: ImpersonationSessionCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = ImpersonationSessionProjection::new(
            event.id,
            event.admin_id,
            event.target_user_id,
            event.session_id,
            event.started_at,
            event.ended_at,
            event.max_duration_minutes,
            event.reason,
            event.actions_performed,
            event.terminated_by,
            event.termination_reason,
            event.status,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: ImpersonationSessionUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.admin_id = event.admin_id;
            projection.target_user_id = event.target_user_id;
            projection.session_id = event.session_id;
            projection.started_at = event.started_at;
            projection.ended_at = event.ended_at;
            projection.max_duration_minutes = event.max_duration_minutes;
            projection.reason = event.reason;
            projection.actions_performed = event.actions_performed;
            projection.terminated_by = event.terminated_by;
            projection.termination_reason = event.termination_reason;
            projection.status = event.status;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: ImpersonationSessionDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

